const areas = results['node_1777720465395'].data.seatLayoutData.areas;
const sessionId = results['node_1777674821623'].data.cinemas[0].experiences[0].sessions[0].id;

const tickets = areas.map(area => {
	const available = area.rows
	  .flatMap(r => r.seats)
	  .filter(s => !s.isDisabled && s.seatStyle !== 'EMPTY');
	const picked = available.sort(() => Math.random() - 0.5).slice(0, 2);
	return {
	  price: area.ticket.price,
	  ticketTypeCode: area.ticket.ticketTypeCode,
	  description: area.description,
	  seats: picked.map(s => ({
		seatsInGroup: [],
		position: s.position,
		isDisabled: false,
		seatStyle: s.seatStyle
	  }))
	};
});

return { sessionId, tickets };
